import { useEffect, useState } from "react";
import {
  getUsers,
  createEmployee,
  updateUser,
  blockUser,
  deleteEmployee,
} from "../../api/adminApi";
import DashboardLayout from "../../components/layout/DashboardLayout";
import ConfirmModal from "../../components/ConfirmModal";
import ErrorModal from "../../components/ErrorModal";
import { Pencil, Plus, ShieldOff, Trash2 } from "lucide-react";

export default function UsersPage() {
  const [users, setUsers] = useState([]);
  const [filters, setFilters] = useState({ role: "", status: "" });

  const [modalOpen, setModalOpen] = useState(false);
  const [modalAction, setModalAction] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);

  const [formOpen, setFormOpen] = useState(false);
  const [editMode, setEditMode] = useState(false);

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    fullName: "",
    phone: "",
    roleName: "COURIER",
  });

  const [errorModal, setErrorModal] = useState({ isOpen: false, message: "" });

  useEffect(() => {
    loadUsers();
  }, [filters]);

  const loadUsers = async () => {
    const params = {};
    if (filters.role) params.roleName = filters.role;
    if (filters.status) params.statusName = filters.status;

    const data = await getUsers(params);
    setUsers(data.content || []);
  };

  const openCreate = () => {
    setEditMode(false);
    setFormData({ email: "", password: "", fullName: "", phone: "", roleName: "COURIER" });
    setFormOpen(true);
  };

  const openEdit = (user) => {
    setEditMode(true);
    setSelectedUser(user);
    setFormData({
      email: user.email,
      fullName: user.fullName,
      phone: user.phone,
      roleName: user.role,
    });
    setFormOpen(true);
  };

  const handleSubmit = async () => {
    try {
      if (editMode) {
        await updateUser(selectedUser.id, formData);
      } else {
        if (formData.roleName === "CLIENT") {
          throw new Error("Нельзя создавать клиентов");
        }
        await createEmployee(formData);
      }
      setFormOpen(false);
      loadUsers();
    } catch (e) {
      setErrorModal({ isOpen: true, message: e.message });
    }
  };

  return (
    <DashboardLayout>
      <div className="p-6 space-y-6">
        <div className="flex justify-between items-center">
          <h1 className="text-3xl font-bold bg-gradient-to-r from-indigo-500 to-purple-500 text-transparent bg-clip-text">
            Управление пользователями
          </h1>

          <button
            onClick={openCreate}
            className="flex items-center gap-2 px-4 py-2 rounded-2xl bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg hover:scale-105 transition"
          >
            <Plus size={18} /> Добавить
          </button>
        </div>

        {/* Filters */}
        <div className="flex gap-4 bg-white p-4 rounded-2xl shadow">
          <select
            className="p-2 border rounded-xl"
            onChange={(e) => setFilters({ ...filters, role: e.target.value })}
          >
            <option value="">Все роли</option>
            <option value="ADMIN">ADMIN</option>
            <option value="LOGIST">LOGIST</option>
            <option value="COURIER">COURIER</option>
          </select>

          <select
            className="p-2 border rounded-xl"
            onChange={(e) => setFilters({ ...filters, status: e.target.value })}
          >
            <option value="">Все статусы</option>
            <option value="Активен">Активен</option>
            <option value="Заблокирован">Заблокирован</option>
          </select>
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl shadow overflow-hidden">
          <table className="w-full">
            <thead className="bg-gradient-to-r from-indigo-500 to-purple-500 text-white">
              <tr>
                <th className="p-3">ID</th>
                <th>Email</th>
                <th>Имя</th>
                <th>Роль</th>
                <th>Статус</th>
                <th>Действия</th>
              </tr>
            </thead>

            <tbody>
              {users.map((u) => (
                <tr key={u.id} className="text-center border-t hover:bg-gray-50">
                  <td>{u.id}</td>
                  <td>{u.email}</td>
                  <td>{u.fullName}</td>
                  <td>{u.role}</td>
                  <td>
                    <span
                      className={`px-3 py-1 rounded-full text-sm ${
                        u.status === "Активен"
                          ? "bg-green-100 text-green-600"
                          : "bg-red-100 text-red-600"
                      }`}
                    >
                      {u.status}
                    </span>
                  </td>

                  <td className="flex gap-2 justify-center p-2">
                    <button onClick={() => openEdit(u)} className="p-2 hover:bg-gray-200 rounded-lg">
                      <Pencil size={16} />
                    </button>

                    <button
                      onClick={() => blockUser(u.id, u.status === "Активен")}
                      className="p-2 hover:bg-gray-200 rounded-lg"
                    >
                      <ShieldOff size={16} />
                    </button>

                    <button
                      onClick={() => deleteEmployee(u.id)}
                      className="p-2 hover:bg-red-100 rounded-lg text-red-500"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Form Modal */}
        {formOpen && (
          <div className="fixed inset-0 bg-black/40 flex items-center justify-center">
            <div className="bg-white p-6 rounded-2xl w-[400px] space-y-4">
              <h2 className="text-xl font-bold">
                {editMode ? "Редактирование" : "Создание"}
              </h2>

              <input placeholder="Email" className="w-full p-2 border rounded" value={formData.email}
                onChange={(e)=>setFormData({...formData,email:e.target.value})} />

              {!editMode && (
                <input type="password" placeholder="Пароль" className="w-full p-2 border rounded"
                  onChange={(e)=>setFormData({...formData,password:e.target.value})} />
              )}

              <input placeholder="Имя" className="w-full p-2 border rounded" value={formData.fullName}
                onChange={(e)=>setFormData({...formData,fullName:e.target.value})} />

              <input placeholder="Телефон" className="w-full p-2 border rounded" value={formData.phone}
                onChange={(e)=>setFormData({...formData,phone:e.target.value})} />

              <select className="w-full p-2 border rounded"
                value={formData.roleName}
                onChange={(e)=>setFormData({...formData,roleName:e.target.value})}>
                <option value="COURIER">COURIER</option>
                <option value="LOGIST">LOGIST</option>
                <option value="ADMIN">ADMIN</option>
              </select>

              <div className="flex justify-end gap-2">
                <button onClick={()=>setFormOpen(false)}>Отмена</button>
                <button onClick={handleSubmit} className="bg-indigo-500 text-white px-4 py-2 rounded">
                  Сохранить
                </button>
              </div>
            </div>
          </div>
        )}

        <ErrorModal
          isOpen={errorModal.isOpen}
          title="Ошибка"
          message={errorModal.message}
          onClose={() => setErrorModal({ isOpen: false, message: "" })}
        />
      </div>
    </DashboardLayout>
  );
}


